class Solution(object):
    def alphabetBoardPath(self, target):
        board = ["abcde", "fghij", "klmno", "pqrst", "uvwxy", "z"]
        pos = {c: (i, j) for i, row in enumerate(board) for j, c in enumerate(row)}
        result = ""
        r, c = 0, 0
        for char in target:
            nr, nc = pos[char]
            while r != nr or c != nc:
                if r < nr:
                    result += "D"
                    r += 1
                elif r > nr:
                    result += "U"
                    r -= 1
                elif c < nc:
                    result += "R"
                    c += 1
                elif c > nc:
                    result += "L"
                    c -= 1
            result += "!"
        return result
